function rand(arr){
    return arr[Math.floor(Math.random() * arr.length)];
}

function getRarity(){

    const rarities = [
        {name:"Common",        class:"common",        value:1,      weight:1000},
        {name:"Uncommon",      class:"uncommon",      value:3,      weight:500},
        {name:"Rare",          class:"rare",           value:8,      weight:250},
        {name:"Epic",          class:"epic",           value:20,     weight:120},
        {name:"Legendary",     class:"legendary",     value:50,     weight:55},
        {name:"Mythic",        class:"mythic",        value:100,    weight:25},
        {name:"Divine",        class:"divine",        value:200,    weight:11},
        {name:"Celestial",     class:"celestial",     value:400,    weight:5},
        {name:"Transcendent",  class:"transcendent",  value:800,    weight:2.2},
        {name:"Ethereal",      class:"ethereal",      value:1500,   weight:1},
        {name:"Abyssal",       class:"abyssal",       value:3000,   weight:0.45},
        {name:"Chrono",        class:"chrono",        value:6000,   weight:0.2},
        {name:"Voidborn",      class:"voidborn",      value:12000,  weight:0.09},
        {name:"Omniversal",    class:"omniversal",    value:25000,  weight:0.04},
        {name:"TUFF GOD",      class:"tuffgod",       value:100000, weight:0.015},
        {name:"Limbo",         class:"limbo",         value:500000, weight:0.004}
    ];

    // Sort rarest first (index 0 = TUFF GOD, last index = Common)
    const sorted = [...rarities].sort((a, b) => a.weight - b.weight);
    const N = sorted.length;

    // Each tier gets a luck multiplier based on how rare it is.
    // rareFactor=1 for TUFF GOD, rareFactor=0 for Common.
    // At 0% luck all mults=1 so original weights are unchanged.
    // At higher luck, rare tiers gain exponentially more weight vs common ones.
    const boosted = sorted.map((r, i) => {
        const rareFactor = (N - 1 - i) / (N - 1);
        const mult = Math.pow(1 + luckBoost, rareFactor * 3);
        return { rarity: r, w: r.weight * mult };
    });

    const total = boosted.reduce((sum, r) => sum + r.w, 0);
    const roll = Math.random() * total;
    let cum = 0;
    for(const entry of boosted){
        cum += entry.w;
        if(roll < cum) return entry.rarity;
    }

    return sorted[N - 1].rarity;
}

// Returns a Promise that resolves when the animation fully finishes
// generate() awaits this so rolls cannot fire during any animation
function triggerOverlay(rarity){
    return new Promise((resolve) => {

        const overlay = document.getElementById("rarityOverlay");
        const body = document.body;

        if(!overlay){ resolve(); return; }

        overlay.className = "";

        if(rarity.class === "omniversal"){
            overlay.classList.add("overlay-active","omniversal-overlay");
        }

        if(rarity.class === "limbo"){
            overlay.classList.add("overlay-active","limbo-overlay");
            playLimboMinigame().then((won) => {
                overlay.classList.remove("overlay-active","limbo-overlay");
                body.style.animation = "";
                if(won){
                    // Grant the Limbo Aura — add to inventory as special item
                    if(!inventory["Limbo Aura"]) inventory["Limbo Aura"] = 0;
                    inventory["Limbo Aura"]++;
                    updateInventory();
                    coins += 500000;
                    updateCoins();
                }
                resolve();
            });
            return;
        }

        if(rarity.class === "tuffgod"){
            overlay.classList.add("overlay-active","tuffgod-overlay");
            playSkibidiAnimation().then(() => {
                overlay.classList.remove("overlay-active","tuffgod-overlay");
                body.style.animation = "";
                resolve();
            });
            return; // tuffgod resolves via playSkibidiAnimation
        }

        if(rarity.class === "mythic" || rarity.class === "divine"){
            body.style.animation = "cosmicWarp 1s ease";
        }

        if(rarity.class === "abyssal" || rarity.class === "chrono"){
            body.style.animation = "voidCollapse 1s ease";
        }

        if(rarity.class === "celestial"){
            body.style.animation = "beam 1s ease";
        }

        if(rarity.class === "abyssal"){
            const flood = document.getElementById("abyssalFlood");
            if(flood){
                flood.classList.add("active");
                setTimeout(() => flood.classList.remove("active"), 1400);
            }
        }

        if(rarity.class === "celestial"){
            const sky = document.getElementById("celestialSky");
            if(sky){
                sky.classList.add("active");
                setTimeout(() => sky.classList.remove("active"), 2000);
            }
        }

        const duration = rarity.class === "celestial" ? 2000 : 1600;
        setTimeout(() => {
            overlay.classList.remove(
                "overlay-active",
                "omniversal-overlay",
                "tuffgod-overlay"
            );
            body.style.animation = "";
            resolve();
        }, duration);
    });
}

/* -------- SKIBIDI TOILET TUFF GOD ANIMATION -------- */

function playSkibidiAnimation(){
    return new Promise((resolve) => {

        let canvas = document.getElementById("skibidiCanvas");
        if(canvas) canvas.remove();

        canvas = document.createElement("canvas");
        canvas.id = "skibidiCanvas";
        // Direct on body, z-index 99999 beats your existing 9999 overlays
        // position:fixed works on body-level elements even in most sandboxes
        canvas.style.cssText = "position:fixed;top:0;left:0;width:100vw;height:100vh;z-index:99999;pointer-events:none;";
        document.body.appendChild(canvas);

        canvas.width  = window.innerWidth;
        canvas.height = window.innerHeight;

        const W = canvas.width;
        const H = canvas.height;
        const ctx = canvas.getContext("2d");

        let frame = 0;
        const TOTAL = 200; // ~3.3s at 60fps
        const lasers = [];
        let toiletX = -180;
        const toiletY = H * 0.5;
        let phase = "walk";

        function addLaser(){
            const angle = (Math.random() - 0.5) * 1.2;
            lasers.push({ x: toiletX + 110, y: toiletY - 80, angle, life: 1.0,
                          color: `hsl(${Math.random()*80+160},100%,65%)` });
        }

        function drawBg(){
            const flash = phase === "shoot" ? Math.abs(Math.sin(frame * 0.4)) * 60 : 0;
            ctx.fillStyle = `rgb(${flash},0,${Math.floor(flash * 0.3)})`;
            ctx.fillRect(0, 0, W, H);

            ctx.save();
            ctx.textAlign = "center";
            ctx.font = `bold ${Math.floor(W * 0.09)}px Impact, sans-serif`;
            const pulse = 1 + Math.sin(frame * 0.12) * 0.04;
            ctx.scale(pulse, pulse);
            ctx.fillStyle = "#ffd700";
            ctx.fillText("TUFF GOD", W / 2 / pulse, H * 0.22 / pulse);
            ctx.fillStyle = "#ff6600";
            ctx.font = `bold ${Math.floor(W * 0.045)}px Impact, sans-serif`;
            ctx.fillText("YOU ROLLED THE RAREST", W / 2 / pulse, H * 0.3 / pulse);
            ctx.restore();
        }

        function drawLasers(){
            for(const l of lasers){
                ctx.save();
                ctx.globalAlpha = Math.max(0, l.life);
                ctx.strokeStyle = l.color;
                ctx.lineWidth = 5;
                ctx.beginPath();
                ctx.moveTo(l.x, l.y);
                ctx.lineTo(l.x + Math.cos(l.angle) * W * 1.5,
                           l.y + Math.sin(l.angle) * W * 1.5);
                ctx.stroke();
                ctx.restore();
            }
        }

        function drawToilet(x, y){
            const bob = Math.sin(frame * 0.3) * 5;
            ctx.save();
            ctx.translate(x, y + bob);

            // Bowl
            ctx.fillStyle = "#e0e0e0";
            ctx.beginPath();
            ctx.ellipse(60, 105, 52, 30, 0, 0, Math.PI*2);
            ctx.fill();
            ctx.fillRect(12, 75, 96, 40);

            // Tank
            ctx.fillStyle = "#d4d4d4";
            ctx.fillRect(18, 18, 84, 60);
            ctx.fillStyle = "#bcbcbc";
            ctx.fillRect(13, 13, 94, 10);

            // Seat outline
            ctx.strokeStyle = "#aaa";
            ctx.lineWidth = 5;
            ctx.beginPath();
            ctx.ellipse(60, 88, 46, 20, 0, 0, Math.PI*2);
            ctx.stroke();

            // Eyes (angry)
            const eyeShift = Math.sin(frame * 0.2) * 2;
            ctx.fillStyle = "#ff2222";
            ctx.beginPath(); ctx.ellipse(36+eyeShift, 38, 11, 14, -0.3, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.ellipse(84+eyeShift, 38, 11, 14,  0.3, 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = "#000";
            ctx.beginPath(); ctx.ellipse(36+eyeShift, 40, 5, 7, 0, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.ellipse(84+eyeShift, 40, 5, 7, 0, 0, Math.PI*2); ctx.fill();
            // Eye glints
            ctx.fillStyle = "#fff";
            ctx.beginPath(); ctx.ellipse(38+eyeShift, 36, 2, 3, 0, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.ellipse(86+eyeShift, 36, 2, 3, 0, 0, Math.PI*2); ctx.fill();

            // Grin
            ctx.strokeStyle = "#222";
            ctx.lineWidth = 3;
            ctx.beginPath();
            ctx.moveTo(28, 62);
            ctx.quadraticCurveTo(60, 80, 92, 62);
            ctx.stroke();

            // Teeth
            ctx.fillStyle = "#fff";
            for(let t=0;t<5;t++) ctx.fillRect(32 + t*11, 62, 9, 10);

            // Legs walking
            const swing = Math.sin(frame * 0.28) * 18;
            ctx.fillStyle = "#c8c8c8";
            ctx.save(); ctx.translate(36, 118); ctx.rotate(swing * Math.PI/180);
            ctx.fillRect(-7, 0, 14, 42); ctx.restore();
            ctx.save(); ctx.translate(84, 118); ctx.rotate(-swing * Math.PI/180);
            ctx.fillRect(-7, 0, 14, 42); ctx.restore();

            // Laser barrel (mouth area)
            if(phase === "shoot"){
                const barrelFlash = Math.abs(Math.sin(frame * 0.5));
                ctx.fillStyle = `rgba(0,200,255,${barrelFlash})`;
                ctx.beginPath();
                ctx.ellipse(60, 75, 8, 8, 0, 0, Math.PI*2);
                ctx.fill();
            }

            ctx.restore();
        }

        function tick(){
            ctx.clearRect(0,0,W,H);
            drawBg();

            if(phase === "walk"){
                toiletX += 7;
                if(toiletX > W * 0.3) phase = "shoot";
            } else if(phase === "shoot"){
                if(frame % 5 === 0) addLaser();
                if(frame > 145) phase = "exit";
            } else {
                toiletX += 11;
            }

            for(let i = lasers.length-1; i >= 0; i--){
                lasers[i].life -= 0.015;
                if(lasers[i].life <= 0) lasers.splice(i,1);
            }

            drawLasers();
            drawToilet(toiletX, toiletY - 180);

            frame++;

            if(frame < TOTAL && toiletX < W + 250){
                requestAnimationFrame(tick);
            } else {
                // Fade out
                let alpha = 1;
                const fade = setInterval(() => {
                    alpha -= 0.07;
                    ctx.clearRect(0,0,W,H);
                    ctx.save();
                    ctx.globalAlpha = Math.max(0, alpha);
                    drawBg();
                    ctx.restore();
                    if(alpha <= 0){
                        clearInterval(fade);
                        canvas.remove();
                        resolve();
                    }
                }, 16);
            }
        }

        requestAnimationFrame(tick);
    });
}

function updateInventory(){

    const invDiv = document.getElementById("inventory");
    if(!invDiv) return;

    // Fixed: was double-looping before, now clean
    let html = "<h3>Inventory</h3>";
    for(const key in inventory){
        html += key + ": " + inventory[key] + "<br>";
    }
    invDiv.innerHTML = html;
}

function forceRarity(rarityName){

    const rarities = {
        "Common":"common",
        "Uncommon":"uncommon",
        "Rare":"rare",
        "Epic":"epic",
        "Legendary":"legendary",
        "Mythic":"mythic",
        "Divine":"divine",
        "Celestial":"celestial",
        "Transcendent":"transcendent",
        "Ethereal":"ethereal",
        "Abyssal":"abyssal",
        "Chrono":"chrono",
        "Voidborn":"voidborn",
        "Omniversal":"omniversal",
        "TUFF GOD":"tuffgod"
    };

    // Value map so forced rolls actually give coins
    const values = {
        "common":1,"uncommon":3,"rare":8,"epic":20,"legendary":50,
        "mythic":100,"divine":200,"celestial":400,"transcendent":800,
        "ethereal":1500,"abyssal":3000,"chrono":6000,"voidborn":12000,
        "omniversal":25000,"tuffgod":100000
    };

    const resultDiv = document.getElementById("result");
    const rarityDiv = document.getElementById("rarity");

    const className = rarities[rarityName];

    if(!className){
        console.log("Invalid rarity name");
        return;
    }

    const rarity = {
        name: rarityName,
        class: className,
        value: values[className] || 0  // Fixed: forced rolls now give proper coins
    };

    resultDiv.innerText = "FORCED ROLL";
    rarityDiv.innerText = rarityName;
    rarityDiv.className = className;

    coins += rarity.value;
    updateCoins();

    if(!inventory[rarity.name]) inventory[rarity.name] = 0;
    inventory[rarity.name]++;
    updateInventory();

    triggerOverlay(rarity);

    console.log("Forced rarity:", rarityName);
}

async function generate(){
    if(isRolling) return;
    
    isRolling = true;
    
    const resultDiv = document.getElementById("result");
    const rarityDiv = document.getElementById("rarity");

    resultDiv.innerText = "Rolling...";
    rarityDiv.innerText = "";
    resultDiv.className = "";

    await new Promise(r => setTimeout(r, 1500));

    const name =
        rand(finn_list) + " " +
        rand(henrico_list) + " " +
        rand(corne_list) + " " +
        rand(borsboom_list);

    const rarity = getRarity();

    resultDiv.innerText = name;
    rarityDiv.innerText = rarity.name;
    rarityDiv.className = rarity.class;

    // Await the full animation — auto-roller cannot fire until this resolves
    await triggerOverlay(rarity);

    if(!inventory[rarity.name]) inventory[rarity.name] = 0;
    inventory[rarity.name]++;
    updateInventory();

    coins += rarity.value;
    updateCoins();
    isRolling = false;
}

function updateCoins(){
    document.getElementById("coins").innerText = coins;
}

function updateLuckDisplay(){
    document.getElementById("luckDisplay").innerText =
        "Luck: " + (luckBoost * 100).toFixed(1) + "%";
}

/* -------- SHOP -------- */

function upgradeLuck(){
    if(coins >= luckPrice){
        coins -= luckPrice;
        luckLevel++;
        luckBoost += 0.01;

        luckPrice = Math.floor(luckPrice * 1.6);

        updateCoins();
        document.getElementById("luckPrice").innerText = luckPrice;
        document.getElementById("luckDisplay").innerText =
            "Luck: " + (Math.min(999999, luckBoost * 100)).toFixed(2) + "%";
    }
}

function upgradeAuto(){
    if(coins >= autoPrice){
        coins -= autoPrice;
        autoLevel++;

        clearInterval(autoInterval);
        let speed = Math.max(500, 3000 - (autoLevel * 200));
        autoInterval = setInterval(generate, speed);

        autoPrice = Math.floor(autoPrice * 1.8);

        updateCoins();
        document.getElementById("autoPrice").innerText = autoPrice;
    }
}

/* -------- DEV MODE -------- */

function redeemCode(){
    const code = document.getElementById("codeBox").value;

    if(code.toLowerCase() === "tuff"){
        devMode = true;
        coins += 10000;
        luckBoost += 0.3;
        updateCoins();
        updateLuckDisplay();
        alert("DEV MODE ACTIVATED 😈");
    }
}


/* -------- LIMBO MINIGAME -------- */
// Inspired by the GD Limbo level key sections:
// A key rotates around a lock. You must click when the key is aligned

/* -------- LIMBO MINIGAME -------- */
// 8 keys float around. One pulses GREEN — memorize it.
// They scramble positions and all get colored (red/blue/orange etc).

/* -------- LIMBO MINIGAME -------- */
// Music-driven: keys spin at 4s, scramble ends + colored at 14s

function playLimboMinigame(){
    return new Promise((resolve) => {

        const overlay = document.getElementById('rarityOverlay');
        overlay.innerHTML = '';

        const W = window.innerWidth;
        const H = window.innerHeight;

        const canvas = document.createElement('canvas');
        canvas.width  = W;
        canvas.height = H;
        canvas.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;cursor:pointer;';
        overlay.appendChild(canvas);
        const ctx = canvas.getContext('2d');

        // ── Audio setup ──────────────────────────────────────
        const audio = new Audio('data:audio/mp3;base64,');
        audio.volume = 0.85;
        audio.play().catch(function(){});

        // Beat timing (in seconds)
        const SPIN_START   = 4.0;   // keys start rotating
        const SCRAMBLE_END = 14.0;  // scramble ends, keys become colored
        const SONG_END     = 21.8;  // fade out

        // ── Constants ────────────────────────────────────────
        const NUM_KEYS     = 8;
        const TOTAL_ROUNDS = 1; // one shot — memorize during spin, pick after color reveal
        const KEY_COLORS   = ['#ff2222','#2288ff','#ff8800','#ffee00','#00ffaa','#ff44cc','#aa44ff','#ffffff'];

        // ── State ────────────────────────────────────────────
        let phase       = 'intro';   // intro|spin|scramble|pick|fail|win
        let frameCount  = 0;
        let won         = false;
        let correctIdx  = 0;
        let animId      = null;
        let flashAlpha  = 0;
        let flashColor  = '#fff';
        let clickLocked = false;
        let winTimer    = 0;
        let spinAngle   = 0; // global rotation angle for all keys around center

        // ── Background ───────────────────────────────────────
        let bgStars = [];
        for(let i=0;i<120;i++) bgStars.push({
            x:Math.random()*W, y:Math.random()*H,
            s:Math.random()*1.6+0.3, sp:Math.random()*0.35+0.05
        });
        let diamonds = [];
        for(let i=0;i<18;i++) diamonds.push({
            x:Math.random()*W, y:Math.random()*H,
            size:Math.random()*18+8, alpha:Math.random()*0.35+0.1,
            sp:(Math.random()-0.5)*0.35
        });
        let bgScroll = 0;

        // ── Keys ─────────────────────────────────────────────
        let keys = [];
        const CX = W * 0.62;
        const CY = H * 0.5;
        const RING_R = Math.min(W,H) * 0.26;

        function spawnKeys(){
            keys = [];
            correctIdx = Math.floor(Math.random() * NUM_KEYS);
            for(let i=0;i<NUM_KEYS;i++){
                const baseAngle = (i / NUM_KEYS) * Math.PI * 2;
                keys.push({
                    id:         i,
                    baseAngle:  baseAngle,   // position on ring
                    x:          CX + Math.cos(baseAngle) * RING_R,
                    y:          CY + Math.sin(baseAngle) * RING_R,
                    color:      '#881100',
                    finalColor: KEY_COLORS[i],
                    isCorrect:  i === correctIdx,
                    // scramble lerp
                    startX: 0, startY: 0,
                    tx: 0, ty: 0,
                    scale: 1,
                    // idle drift (before spin)
                    driftX: (Math.random()-0.5)*0.35,
                    driftY: (Math.random()-0.5)*0.35
                });
            }
        }

        function assignScrambleTargets(){
            // Shuffle positions across the ring randomly
            let angles = keys.map(function(k){ return k.baseAngle; });
            for(let i=angles.length-1;i>0;i--){
                const j=Math.floor(Math.random()*(i+1));
                var tmp=angles[i]; angles[i]=angles[j]; angles[j]=tmp;
            }
            for(let i=0;i<keys.length;i++){
                keys[i].startX = keys[i].x;
                keys[i].startY = keys[i].y;
                keys[i].tx = CX + Math.cos(angles[i]) * RING_R;
                keys[i].ty = CY + Math.sin(angles[i]) * RING_R;
            }
        }

        // ── Draw helpers ─────────────────────────────────────
        function drawBg(){
            ctx.fillStyle = '#0d0000';
            ctx.fillRect(0,0,W,H);
            var grad = ctx.createRadialGradient(W/2,H/2,0,W/2,H/2,W*0.6);
            grad.addColorStop(0,'rgba(80,0,0,0.5)');
            grad.addColorStop(1,'rgba(0,0,0,0)');
            ctx.fillStyle = grad;
            ctx.fillRect(0,0,W,H);
            for(var i=0;i<diamonds.length;i++){
                var d=diamonds[i];
                d.x+=d.sp; if(d.x>W+20) d.x=-20;
                ctx.save();
                ctx.globalAlpha=d.alpha;
                ctx.translate(d.x,d.y);
                ctx.rotate(Math.PI/4);
                ctx.fillStyle='#cc2200';
                ctx.fillRect(-d.size/2,-d.size/2,d.size,d.size);
                ctx.restore();
            }
            // connecting lines
            ctx.strokeStyle='rgba(180,40,0,0.15)';
            ctx.lineWidth=1;
            for(var a=0;a<keys.length;a++){
                for(var b=a+1;b<keys.length;b++){
                    var dx=keys[a].x-keys[b].x, dy=keys[a].y-keys[b].y;
                    if(Math.sqrt(dx*dx+dy*dy)<W*0.38){
                        ctx.beginPath();
                        ctx.moveTo(keys[a].x,keys[a].y);
                        ctx.lineTo(keys[b].x,keys[b].y);
                        ctx.stroke();
                    }
                }
            }
            bgScroll++;
        }

        function drawKey(k){
            ctx.save();
            ctx.translate(k.x, k.y);
            ctx.scale(k.scale, k.scale);

            var col = k.color;
            if((phase==='intro'||phase==='spin') && k.isCorrect){
                var pulse = 0.5+0.5*Math.sin(frameCount*0.18);
                col = 'hsl(120,100%,'+(Math.floor(45+pulse*30))+'%)';
                ctx.shadowColor = '#00ff44';
                ctx.shadowBlur  = 15+pulse*22;
            } else {
                ctx.shadowColor = col;
                ctx.shadowBlur  = 8;
            }

            // Head circle
            ctx.beginPath();
            ctx.arc(0,0,9,0,Math.PI*2);
            ctx.strokeStyle=col; ctx.lineWidth=2.5; ctx.stroke();
            // Keyhole
            ctx.beginPath();
            ctx.arc(0,0,3.5,0,Math.PI*2);
            ctx.strokeStyle=col; ctx.lineWidth=1.5; ctx.stroke();
            // Shaft
            ctx.beginPath();
            ctx.moveTo(0,9); ctx.lineTo(0,26);
            ctx.strokeStyle=col; ctx.lineWidth=2.5; ctx.stroke();
            // Teeth
            ctx.beginPath();
            ctx.moveTo(0,16); ctx.lineTo(5,16);
            ctx.moveTo(0,21); ctx.lineTo(5,21);
            ctx.strokeStyle=col; ctx.lineWidth=2; ctx.stroke();

            ctx.shadowBlur=0;
            ctx.restore();
        }

        function drawAllKeys(){
            for(var i=0;i<keys.length;i++) drawKey(keys[i]);
        }

        function drawHUD(){
            ctx.textAlign='center';
            ctx.font='bold '+Math.floor(W*0.07)+'px Impact, Arial';
            ctx.fillStyle='#cc2200';
            ctx.shadowColor='#ff4400'; ctx.shadowBlur=18;
            ctx.fillText('LIMBO',W/2,H*0.13);
            ctx.shadowBlur=0;

            if(phase==='intro'||phase==='spin'){
                ctx.font='bold '+Math.floor(W*0.024)+'px Arial';
                ctx.fillStyle='#00ff88';
                ctx.shadowColor='#00ff88'; ctx.shadowBlur=10;
                ctx.fillText('Memorize the GREEN key!',W/2,H*0.88);
                ctx.shadowBlur=0;
            }
            if(phase==='pick'){
                ctx.font='bold '+Math.floor(W*0.026)+'px Arial';
                ctx.fillStyle='#ffcc00';
                ctx.shadowColor='#ffcc00'; ctx.shadowBlur=10;
                ctx.fillText('Which key was green? CLICK IT!',W/2,H*0.88);
                ctx.shadowBlur=0;
            }
        }

        function drawFlash(){
            if(flashAlpha>0){
                ctx.fillStyle=flashColor;
                ctx.globalAlpha=flashAlpha*0.55;
                ctx.fillRect(0,0,W,H);
                ctx.globalAlpha=1;
                flashAlpha-=0.05;
            }
        }

        function drawWin(){
            var cx=W/2, cy=H*0.44;
            for(var i=0;i<6;i++){
                var rad=45+i*28+Math.sin(frameCount*0.07+i)*8;
                var hue=(frameCount*3+i*55)%360;
                ctx.strokeStyle='hsl('+hue+',100%,65%)';
                ctx.lineWidth=2.5;
                ctx.beginPath(); ctx.arc(cx,cy,rad,0,Math.PI*2); ctx.stroke();
            }
            ctx.textAlign='center';
            ctx.font='bold '+Math.floor(W*0.07)+'px Impact, Arial';
            ctx.fillStyle='#ffcc00';
            ctx.shadowColor='#ffcc00'; ctx.shadowBlur=35;
            ctx.fillText('LIMBO AURA',cx,H*0.22);
            ctx.shadowBlur=0;
            ctx.font=Math.floor(W*0.025)+'px Arial';
            ctx.fillStyle='#fff';
            ctx.fillText('Added to your inventory!',cx,H*0.3);
            var g=ctx.createRadialGradient(cx,cy,0,cx,cy,58);
            g.addColorStop(0,'#ffffff');
            g.addColorStop(0.4,'#cc44ff');
            g.addColorStop(1,'rgba(0,0,0,0)');
            ctx.shadowColor='#cc44ff';
            ctx.shadowBlur=22+Math.sin(frameCount*0.09)*12;
            ctx.fillStyle=g;
            ctx.beginPath(); ctx.arc(cx,cy,58,0,Math.PI*2); ctx.fill();
            ctx.shadowBlur=0;
        }

        function drawFail(){
            ctx.textAlign='center';
            ctx.font='bold '+Math.floor(W*0.055)+'px Impact';
            ctx.fillStyle='#ff2222';
            ctx.shadowColor='#ff2222'; ctx.shadowBlur=22;
            ctx.fillText('WRONG KEY.',W/2,H*0.82);
            ctx.shadowBlur=0;
            ctx.font=Math.floor(W*0.022)+'px Arial';
            ctx.fillStyle='#ffaaaa';
            ctx.fillText('The Limbo Aura slips away...',W/2,H*0.9);
        }

        // ── Click ─────────────────────────────────────────────
        function handleClick(e){
            if(phase!=='pick'||clickLocked) return;
            var rect=canvas.getBoundingClientRect();
            var mx=(e.clientX-rect.left)*(W/rect.width);
            var my=(e.clientY-rect.top)*(H/rect.height);
            var hit=null;
            for(var i=0;i<keys.length;i++){
                var dx=mx-keys[i].x, dy=my-keys[i].y;
                if(Math.sqrt(dx*dx+dy*dy)<22){ hit=keys[i]; break; }
            }
            if(!hit) return;
            clickLocked=true;

            if(hit.isCorrect){
                flashColor='#00ff88'; flashAlpha=1;
                won=true;
                phase='win';
            } else {
                flashColor='#ff0000'; flashAlpha=1;
                // reveal correct key in green
                for(var i=0;i<keys.length;i++){
                    keys[i].color = keys[i].isCorrect ? '#00ff88' : keys[i].finalColor;
                }
                won=false;
                phase='fail';
                setTimeout(function(){ phase='done'; }, 2000);
            }
        }

        canvas.addEventListener('click', handleClick);

        // ── scramble lerp state ───────────────────────────────
        let scrambleT = 0;
        let scrambling = false;
        let scrambleStarted = false;

        // ── Main loop ─────────────────────────────────────────
        function tick(){
            ctx.clearRect(0,0,W,H);
            var t = audio.currentTime;

            drawBg();

            if(phase==='intro'){
                // Keys drift gently, correct pulses green
                for(var i=0;i<keys.length;i++){
                    keys[i].x += keys[i].driftX;
                    keys[i].y += keys[i].driftY;
                    if(keys[i].x<W*0.3||keys[i].x>W*0.95) keys[i].driftX*=-1;
                    if(keys[i].y<H*0.2||keys[i].y>H*0.85) keys[i].driftY*=-1;
                    keys[i].color='#881100';
                }
                drawAllKeys();
                drawHUD();

                // At 4s: switch to spin
                if(t >= SPIN_START){
                    phase='spin';
                    // Fix key positions evenly on ring for spin
                    for(var i=0;i<keys.length;i++){
                        keys[i].x = CX + Math.cos(keys[i].baseAngle)*RING_R;
                        keys[i].y = CY + Math.sin(keys[i].baseAngle)*RING_R;
                    }
                }

            } else if(phase==='spin'){
                // All keys orbit together around center
                spinAngle += 0.018;
                for(var i=0;i<keys.length;i++){
                    var a = keys[i].baseAngle + spinAngle;
                    keys[i].x = CX + Math.cos(a)*RING_R;
                    keys[i].y = CY + Math.sin(a)*RING_R;
                    keys[i].color='#881100';
                }
                drawAllKeys();
                drawHUD();

                // At 14s: scramble and color
                if(t >= SCRAMBLE_END && !scrambleStarted){
                    scrambleStarted=true;
                    scrambling=true;
                    scrambleT=0;
                    assignScrambleTargets();
                    phase='scramble';
                }

            } else if(phase==='scramble'){
                scrambleT = Math.min(1, scrambleT+0.022);
                var st = scrambleT*scrambleT*(3-2*scrambleT);
                for(var i=0;i<keys.length;i++){
                    keys[i].x = keys[i].startX + (keys[i].tx-keys[i].startX)*st;
                    keys[i].y = keys[i].startY + (keys[i].ty-keys[i].startY)*st;
                    keys[i].scale = 1+Math.sin(scrambleT*Math.PI)*0.2;
                    keys[i].color = '#881100';
                }
                drawAllKeys();

                if(scrambleT>=1){
                    // Color reveal
                    for(var i=0;i<keys.length;i++){
                        keys[i].color = keys[i].finalColor;
                        keys[i].scale = 1;
                    }
                    phase='pick';
                    clickLocked=false;
                }

            } else if(phase==='pick'){
                for(var i=0;i<keys.length;i++){
                    keys[i].x += keys[i].driftX*0.4;
                    keys[i].y += keys[i].driftY*0.4;
                    if(keys[i].x<W*0.3||keys[i].x>W*0.95) keys[i].driftX*=-1;
                    if(keys[i].y<H*0.2||keys[i].y>H*0.85) keys[i].driftY*=-1;
                }
                drawAllKeys();
                drawHUD();

            } else if(phase==='fail'){
                drawAllKeys();
                drawFlash();
                drawFail();

            } else if(phase==='win'){
                winTimer++;
                drawWin();
                if(winTimer>170){ phase='done'; }

            } else if(phase==='done'){
                cancelAnimationFrame(animId);
                canvas.removeEventListener('click',handleClick);
                audio.pause();
                var alpha=1;
                var fade=setInterval(function(){
                    alpha-=0.07;
                    ctx.clearRect(0,0,W,H);
                    ctx.globalAlpha=Math.max(0,alpha);
                    drawBg();
                    ctx.globalAlpha=1;
                    if(alpha<=0){
                        clearInterval(fade);
                        overlay.innerHTML='';
                        resolve(won);
                    }
                },16);
                return;
            }

            drawFlash();
            frameCount++;
            animId=requestAnimationFrame(tick);
        }

        spawnKeys();
        requestAnimationFrame(tick);
    });
}
